import os
import hashlib
from prometheus_client import Gauge, start_http_server
import time

# Secure implementation - DO NOT expose credentials in metrics
# Instead, use hashed identifiers and connection status monitoring

db_connection_status = Gauge(
    'database_connection_status',
    'Database connection health status (1=healthy, 0=unhealthy)',
    ['db_identifier', 'host', 'port']
)

db_connection_latency = Gauge(
    'database_connection_latency_seconds',
    'Database connection latency in seconds',
    ['db_identifier', 'host', 'port']
)

db_connection_pool_size = Gauge(
    'database_connection_pool_size',
    'Current database connection pool size',
    ['db_identifier', 'host', 'port']
)

db_connection_pool_available = Gauge(
    'database_connection_pool_available',
    'Available connections in the pool',
    ['db_identifier', 'host', 'port']
)


def get_db_identifier(username, host, database):
    """Create a secure hash-based identifier for the database connection"""
    identifier_string = f"{username}@{host}/{database}"
    return hashlib.sha256(identifier_string.encode()).hexdigest()[:16]


def check_database_connection(host, port, username, password, database):
    """
    Check database connection health without exposing credentials
    Returns: (status, latency)
    """
    try:
        import psycopg2
        start_time = time.time()
        
        conn = psycopg2.connect(
            host=host,
            port=port,
            user=username,
            password=password,
            database=database,
            connect_timeout=5
        )
        
        latency = time.time() - start_time
        
        cursor = conn.cursor()
        cursor.execute("SELECT 1")
        cursor.close()
        conn.close()
        
        return 1, latency
    except Exception as e:
        print(f"Connection check failed: {e}")
        return 0, 0


def monitor_database_connections():
    """
    Monitor database connections securely
    Credentials should be loaded from secure sources like:
    - Environment variables
    - Secret management systems (HashiCorp Vault, AWS Secrets Manager)
    - Encrypted configuration files
    """
    
    # Example: Load credentials from environment variables (secure approach)
    databases = [
        {
            'host': os.getenv('DB_HOST', 'localhost'),
            'port': os.getenv('DB_PORT', '5432'),
            'username': os.getenv('DB_USERNAME', 'postgres'),
            'password': os.getenv('DB_PASSWORD', ''),
            'database': os.getenv('DB_NAME', 'postgres')
        }
    ]
    
    while True:
        for db_config in databases:
            host = db_config['host']
            port = db_config['port']
            username = db_config['username']
            password = db_config['password']
            database = db_config['database']
            
            # Create secure identifier instead of exposing credentials
            db_id = get_db_identifier(username, host, database)
            
            # Check connection health
            status, latency = check_database_connection(
                host, port, username, password, database
            )
            
            # Update metrics with ONLY non-sensitive information
            db_connection_status.labels(
                db_identifier=db_id,
                host=host,
                port=port
            ).set(status)
            
            if status == 1:
                db_connection_latency.labels(
                    db_identifier=db_id,
                    host=host,
                    port=port
                ).set(latency)
        
        time.sleep(30)


if __name__ == '__main__':
    # Start Prometheus metrics server
    start_http_server(8000)
    print("Prometheus metrics server started on port 8000")
    print("Metrics available at http://localhost:8000/metrics")
    print("\nSECURITY NOTE: This implementation does NOT expose credentials in metrics")
    print("Database connections are identified by secure hash identifiers")
    
    # Start monitoring
    monitor_database_connections()